#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
using namespace std;
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int Mod=1e9+7,N=1e6+10;LL fac[N],Y[N],ifac[N],pre[N],suf[N];
inline LL qpow(LL a,LL b=Mod-2){LL res=1;while(b){b&1?res=res*a%Mod:0;a=a*a%Mod;b=b>>1;}return res;}
inline void Brute(int n,int k)
{
	int ans=0;rep(1,n,i)(ans+=qpow(i,k))%=Mod;
	printf("%d\n",ans);return;
}
int main()
{
	int n=read(),k=read()+2;
	if(n<=1000010){Brute(n,k-2);return 0;}
	fac[0]=fac[1]=1;rep(2,k,i)fac[i]=fac[i-1]*i%Mod;
	ifac[0]=ifac[1]=1;rep(2,k,i)ifac[i]=qpow(fac[i]);
	Y[0]=0;Y[1]=1;rep(2,k,i)Y[i]=(Y[i-1]+qpow(i,k-2))%Mod;
	pre[0]=1;rep(1,k,i)pre[i]=pre[i-1]*(n-i)%Mod;
	suf[k+1]=1;drep(k,1,i)suf[i]=suf[i+1]*(n-i)%Mod;
	LL ans=0;rep(1,k,i)
	{
		(((k-i)&1)^1)?(ans+=Y[i]*pre[i-1]%Mod*suf[i+1]%Mod*ifac[i-1]%Mod*ifac[k-i]%Mod)%=Mod
		:ans=(ans-Y[i]*pre[i-1]%Mod*suf[i+1]%Mod*ifac[i-1]%Mod*ifac[k-i]%Mod+Mod)%Mod;
	}
	printf("%lld\n",ans);return 0;
}
